import pandas as pd

data = locals()['var_function-call-3012250034672744689']

wifi_businesses = []
state_counts = {}

# Regex for extracting state: "in City, State, this"
# "Located at ... in [City], [State], this..."
state_pattern = re.compile(r",\s([A-Z]{2}),\sthis")

for biz in data:
    attrs = biz.get('attributes')
    desc = biz.get('description', '')

    has_wifi = False
    if isinstance(attrs, dict):
        wifi_val = attrs.get('WiFi')
        if wifi_val:
            # Check for free or paid. Values might be like "u'free'", "'free'", "u'paid'"
            if 'free' in str(wifi_val).lower() or 'paid' in str(wifi_val).lower():
                has_wifi = True

    if has_wifi:
        # Extract state
        match = state_pattern.search(desc)
        if match:
            state = match.group(1)
            if state not in state_counts:
                state_counts[state] = []
            state_counts[state].append(biz['business_id'])

# Find state with max businesses
max_state = None
max_count = 0
for state, biz_list in state_counts.items():
    if len(biz_list) > max_count:
        max_count = len(biz_list)
        max_state = state

result = {
    "max_state": max_state,
    "count": max_count,
    "business_ids": state_counts[max_state] if max_state else []
}

print("__RESULT__:")
print(result) # Only printing the summary structure, beware if business_ids is huge

